mapper.delete:
delete from post_tbl
where post_id = #{postId}
  and deleted_yn = 'Y'

mapper.select:
select count(*)
from hashtag
where hashtag_id = #{hashtagId}

select r.report_id, case when r.post_id is not null then 'POST' else 'COMMENT' end as target_type, r.reporter_member_id, reporter.name as reporter_name, reporter.nickname as reporter_nickname, reporter.email as reporter_email, case when r.post_id is not null then post_author.member_id else comment_author.member_id end as target_member_id, case when r.post_id is not null then post_author.name else comment_author.name end as target_member_name, case when r.post_id is not null then post_author.nickname else comment_author.nickname end as target_member_nickname, case when r.post_id is not null then post_author.email else comment_author.email end as target_member_email, case when r.post_id is not null then post_author.created_at else comment_author.created_at end as target_member_created_at, ( select count(*) from post_tbl target_post_count where target_post_count.member_id = case when r.post_id is not null then post_author.member_id else comment_author.member_id end and coalesce(target_post_count.deleted_yn, 'N') = 'N' ) as target_post_count, ( select count(*) from comment_tbl target_comment_count where target_comment_count.member_id = case when r.post_id is not null then post_author.member_id else comment_author.member_id end and coalesce(target_comment_count.deleted_yn, 'N') = 'N' ) as target_comment_count, ( select count(*) from post_like target_like_count where target_like_count.member_id = case when r.post_id is not null then post_author.member_id else comment_author.member_id end ) as target_like_count, ( select count(*) from report target_report left join post_tbl reported_post on reported_post.post_id = target_report.post_id left join comment_tbl reported_comment on reported_comment.comment_id = target_report.comment_id where coalesce(reported_post.member_id, reported_comment.member_id) = case when r.post_id is not null then post_author.member_id else comment_author.member_id end ) as target_report_count, coalesce( case when r.post_id is not null then post_author.warning_count else comment_author.warning_count end, 0 ) as target_warning_count, ( select count(*) from admin_action_logs target_suspend_log where target_suspend_log.target_type = 'USER' and target_suspend_log.action_type = 'SUSPEND' and target_suspend_log.target_id = case when r.post_id is not null then post_author.member_id else comment_author.member_id end ) as target_suspend_count, r.post_id, r.comment_id, coalesce(post_target.title, comment_post.title) as post_title, ( select group_concat(concat('#', h.hashtag) order by h.hashtag separator ' ') from post_hashtag ph join hashtag h on h.hashtag_id = ph.hashtag_id where ph.post_id = coalesce(post_target.post_id, comment_post.post_id) ) as post_tags, case when r.post_id is not null then post_target.content else comment_target.content end as target_content, comment_target.content as comment_content, r.reason, r.report_status, r.process_result, r.handled_memo, r.handled_by_member_id, handled_member.name as handled_by_member_name, r.reviewed_at, r.handled_at, r.created_at, ( select count(*) from report same_report where ( r.post_id is not null and same_report.post_id = r.post_id ) or ( r.comment_id is not null and same_report.comment_id = r.comment_id ) ) as same_target_report_count, ( select count(distinct same_report.reporter_member_id) from report same_report where ( r.post_id is not null and same_report.post_id = r.post_id ) or ( r.comment_id is not null and same_report.comment_id = r.comment_id ) ) as same_target_reporter_count from report r left join members reporter on reporter.member_id = r.reporter_member_id left join post_tbl post_target on post_target.post_id = r.post_id left join members post_author on post_author.member_id = post_target.member_id left join comment_tbl comment_target on comment_target.comment_id = r.comment_id left join post_tbl comment_post on comment_post.post_id = comment_target.post_id left join members comment_author on comment_author.member_id = comment_target.member_id left join members handled_member on handled_member.member_id = r.handled_by_member_id where 1 = 1
and r.report_status = #{status}
and r.post_id is not null
and r.comment_id is not null
and r.process_result = #{processResult}
order by case when r.report_status = 'DONE' and r.handled_at is not null then r.handled_at when r.report_status = 'REVIEWING' and r.reviewed_at is not null then r.reviewed_at else r.created_at end desc, r.report_id desc

select activity_type as type, activity_text as text, date_format(activity_created_at, '%Y-%m-%d %H:%i') as time from ( select '게시글' as activity_type, coalesce(nullif(p.title, ''), '제목 없는 게시글') as activity_text, p.created_at as activity_created_at from post_tbl p where p.member_id = #{memberId}
union all
select '댓글' as activity_type, coalesce(nullif(c.content, ''), '내용 없는 댓글') as activity_text, c.created_at as activity_created_at from comment_tbl c where c.member_id = #{memberId}
union all
select '제재' as activity_type, coalesce(nullif(log.action_detail, ''), log.action_type) as activity_text, log.created_at as activity_created_at from admin_action_logs log where log.target_type = 'USER' and log.target_id = #{memberId} and log.action_type in ('SUSPEND', 'RESTORE') ) recent_activity order by activity_created_at desc limit 50
